  once<E extends keyof Events>(event: E, listener: (...args: Events[E]) => void): this;
  once(event: '*', listener: (...args: any[]) => void): this;
  once(event: string, listener: (...args: any[]) => void): this {
    const self = this;
    const wrapper = (...args: any[]) => {
      self.off(event, wrapper as any);
      listener(...args);
    };
    const entries = this._getOrCreate(event);
    entries.push({ original: listener, wrapper, once: true });
    return this;
  }

  off<E extends keyof Events>(event: E, listener: (...args: Events[E]) => void): this;
  off(event: '*', listener: (...args: any[]) => void): this;
  off(event: string, listener: (...args: any[]) => void): this {
    const entries = this._listeners.get(event);
    if (entries) {
      const idx = entries.findIndex(e => e.original === listener || e.wrapper === listener);
      if (idx !== -1) {
        entries.splice(idx, 1);
        if (entries.length === 0) {
          this._listeners.delete(event);
        }
      }
    }
    return this;
  }

  emit<E extends keyof Events>(event: E, ...args: Events[E]): boolean {
    return this._emit(event as string, args);
  }

  private _emit(event: string, args: any[]): boolean {
    let hasListeners = false;

    // Emit to wildcard listeners
    const wildcardEntries = this._listeners.get('*');
    if (wildcardEntries) {
      hasListeners = true;
      for (const entry of [...wildcardEntries]) {
        try {
          entry.wrapper(event, ...args);
        } catch (e) {
          // Don't let one listener failure stop others
        }
      }
    }

    // Emit to event-specific listeners
