            const idx = current.indexOf(entry);
            if (idx !== -1) current.splice(idx, 1);
          }
        }
      }
    }

    return hasListeners;
  }

  listenerCount(event: keyof Events | '*'): number {
    return this._listeners.get(event as string)?.length ?? 0;
  }

  removeAll(event?: keyof Events | '*'): this {
    if (event === undefined) {
      this._listeners.clear();
    } else {
      this._listeners.delete(event as string);
    }
    return this;
  }

  private _getOrCreate(event: string): ListenerEntry[] {
    let entries = this._listeners.get(event);
    if (!entries) {
      entries = [];
      this._listeners.set(event, entries);
    }
    return entries;
  }
}
